// packages/backend/src/plugins/catalog/BedrockEntityProvider.ts
// Backstage EntityProvider that auto-imports AWS Bedrock foundation models
// into the catalog on a 1-hour sync interval.

import {
  EntityProvider,
  EntityProviderConnection,
} from "@backstage/plugin-catalog-node";
import { BedrockClient, ListFoundationModelsCommand } from "@aws-sdk/client-bedrock";
import { Entity } from "@backstage/catalog-model";

export class BedrockEntityProvider implements EntityProvider {
  private connection?: EntityProviderConnection;
  private readonly region: string;

  constructor(region = "us-east-1") {
    this.region = region;
  }

  getProviderName(): string {
    return `BedrockEntityProvider:${this.region}`;
  }

  async connect(connection: EntityProviderConnection): Promise<void> {
    this.connection = connection;
    // Initial sync on startup, then every hour
    await this.refresh();
    setInterval(() => this.refresh(), 60 * 60 * 1000);
  }

  private async refresh(): Promise<void> {
    const client = new BedrockClient({ region: this.region });
    const resp = await client.send(new ListFoundationModelsCommand({}));
    const models = resp.modelSummaries ?? [];

    const entities: Entity[] = models.map((m) => ({
      apiVersion: "backstage.io/v1alpha1",
      kind: "Component",
      metadata: {
        name: m.modelId!.replace(/[^a-zA-Z0-9-]/g, "-").toLowerCase(),
        title: m.modelName ?? m.modelId,
        annotations: {
          "ai.platform/provider": "aws-bedrock",
          "ai.platform/model-id": m.modelId ?? "",
          "ai.platform/region": this.region,
          "ai.platform/input-modalities": (m.inputModalities ?? []).join(","),
          "ai.platform/output-modalities": (m.outputModalities ?? []).join(","),
          "backstage.io/managed-by-location": `url:aws-bedrock/${this.region}`,
          "backstage.io/managed-by-origin-location": `url:aws-bedrock/${this.region}`,
        },
        tags: ["llm", "aws-bedrock", "auto-imported"],
      },
      spec: {
        type: "ai-model",
        lifecycle: "production",
        owner: "group:platform-ai",
        system: "genai-platform",
      },
    }));

    // Emit full refresh — Backstage reconciles additions and deletions
    await this.connection!.applyMutation({
      type: "full",
      entities: entities.map((entity) => ({
        entity,
        locationKey: this.getProviderName(),
      })),
    });
  }
}
